import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  // 世界基础信息
  世界: z.object({
    详细地址: z.string().prefault('未知地点'),
    时间: z.object({
      年: z.coerce.number().prefault(2024),
      月: z.coerce.number().prefault(1),
      日: z.coerce.number().prefault(1),
      小时: z.coerce.number().prefault(12),
    }).transform(time => {
      // 自动计算星期
      const date = new Date(time.年, time.月 - 1, time.日);
      const weeks = ['星期日', '星期一', '星期二', '星期三', '星期四', '星期五', '星期六'];
      return { ...time, 星期: weeks[date.getDay()] };
    }),
  }),

  // 角色状态字典，支持多人
  角色列表: z.record(
    z.string().describe('角色名'), // 键名为角色名
    z.object({
      // --- 基础属性 ---
      好感度: z.coerce.number().prefault(0),
      关爱需求值: z.coerce.number().prefault(0),

      // --- 生理状态 ---
      // 使用 Math.max/min 代替 _.clamp 以避免依赖问题
      疼痛值: z.coerce.number().transform(v => Math.max(0, Math.min(100, v))).prefault(0),
      臀部红肿情况: z.string().prefault('完好'),
      性欲度: z.coerce.number().prefault(0),
      高潮度: z.coerce.number().prefault(0),
      尿意: z.coerce.number().prefault(0),

      // --- 心理状态 ---
      羞耻值: z.coerce.number().prefault(0),

      // --- 当前处境 ---
      正在使用的工具: z.record(z.string().describe('工具名'), z.string().describe('使用状态/描述')).prefault({}),
      正在接受的惩罚: z.string().prefault('无'),

    }).transform(role => {
      // --- 自动计算逻辑区域 ---

      // 1. 根据疼痛值计算心理防线区域
      // 0-60% 安全区, 61-90% 崩溃区, 91-100% 临界点
      if (role.疼痛值 <= 60) role.心理防线状态 = '安全区';
      else if (role.疼痛值 <= 90) role.心理防线状态 = '崩溃区';
      else role.心理防线状态 = '临界点';

      // 2. 根据数值计算顺从度阶段
      // 假设逻辑：顺从值 = 好感度 + 疼痛值 (可根据需求调整权重)
      const 顺从计算值 = role.好感度 + role.疼痛值;
      role._内部顺从值 = 顺从计算值; // 保留数值以便观察

      if (顺从计算值 < 50) role.顺从度 = '反抗期';
      else if (顺从计算值 < 150) role.顺从度 = '顺从期';
      else role.顺从度 = '依赖期';

      return role;
    })
  ).prefault({}) // 默认为空字典
});

$(() => {
  registerMvuSchema(Schema);
})
